import React, { useState } from "react";
import api from "../services/api"; // using your existing axios instance
import { useNavigate } from "react-router-dom";
import {
  Box,
  Button,
  CircularProgress,
  Paper,
  TextField,
  Typography,
  Alert,
} from "@mui/material";

export default function Register() {
  const [form, setForm] = useState({ name: "", phone: "", email: "" });
  const [loading, setLoading] = useState(false);
  const [msg, setMsg] = useState("");
  const navigate = useNavigate();

  const submit = async (e) => {
    e.preventDefault();
    setMsg("");
    try {
      setLoading(true);
      // keep the same endpoint you used previously so existing backend behavior is unchanged
      await api.post("/users/register", form);
      setMsg("Registered. Please login.");
      // preserve your original redirect timing/behavior
      setTimeout(() => navigate("/login"), 800);
    } catch (err) {
      setMsg(err?.response?.data?.message || "Registration failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box
      display="flex"
      justifyContent="center"
      alignItems="center"
      minHeight="80vh"
      sx={{ bgcolor: "background.default", p: 2 }}
    >
      <Paper elevation={3} sx={{ p: 4, maxWidth: 520, width: "100%" }}>
        <Typography variant="h5" align="center" gutterBottom>
          Register
        </Typography>

        <Box component="form" onSubmit={submit} noValidate>
          <TextField
            label="Name"
            value={form.name}
            onChange={(e) => setForm({ ...form, name: e.target.value })}
            fullWidth
            margin="normal"
            required
            autoComplete="name"
          />

          <TextField
            label="Phone"
            value={form.phone}
            onChange={(e) => setForm({ ...form, phone: e.target.value })}
            fullWidth
            margin="normal"
            required
            autoComplete="tel"
          />

          <TextField
            label="Email"
            value={form.email}
            onChange={(e) => setForm({ ...form, email: e.target.value })}
            fullWidth
            margin="normal"
            type="email"
            autoComplete="email"
          />

          <Box mt={2} position="relative">
            <Button
              type="submit"
              variant="contained"
              fullWidth
              disabled={loading}
            >
              {loading ? "Registering..." : "Register"}
            </Button>

            {loading && (
              <CircularProgress
                size={24}
                sx={{
                  position: "absolute",
                  top: "50%",
                  left: "50%",
                  mt: "-12px",
                  ml: "-12px",
                }}
              />
            )}
          </Box>
        </Box>

        {msg && (
          <Box mt={2}>
            {/* treat "Registered" as success, anything else as error — keeps behavior consistent */}
            {String(msg).toLowerCase().includes("register") ? (
              <Alert severity="success">{msg}</Alert>
            ) : (
              <Alert severity="error">{msg}</Alert>
            )}
          </Box>
        )}
      </Paper>
    </Box>
  );
}
